    {
      type: 'insertWindowOnWall',
      id: 'hf-win-uf-trap',
      name: 'Upper left trapezoidal window',
      wallId: 'hf-w-uf-s-l',
      alongT: 0.5,
      widthMm: 2500,
      heightMm: 2000,
      sillHeightMm: 500,
