    {
      type: 'createWall',
      id: 'hf-w-gf-e',
      name: 'GF east wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X1, yMm: 0 },
      end: { xMm: GF_X1, yMm: D },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-n',
      name: 'GF north wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X1, yMm: D },
      end: { xMm: GF_X0, yMm: D },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-w',
      name: 'GF west wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X0, yMm: D },
