      type: 'createRoofOpening',
      id: 'hf-roof-cutout',
      name: 'Terrace roof cutout',
      hostRoofId: 'hf-roof-main',
      boundaryMm: [
        { xMm: RIDGE_X, yMm: D / 2 },
        { xMm: UF_X1, yMm: D / 2 },
        { xMm: UF_X1, yMm: D },
        { xMm: RIDGE_X, yMm: D },
