    { type: 'createLevel', id: 'hf-lvl-ground', name: 'Ground Floor', elevationMm: 0 },
    { type: 'createLevel', id: 'hf-lvl-upper', name: 'First Floor', elevationMm: F2F },

    // === PHASE 1: MASSING ===
    {
      type: 'createMass',
      id: 'hf-mass-gf',
      name: 'Ground floor volume',
      levelId: 'hf-lvl-ground',
