      heightMm: 4000,
      materialKey: 'white_render',
    },

    // === PHASE 2: SKELETON ===
    { type: 'deleteElement', elementId: 'hf-mass-gf' },
    { type: 'deleteElement', elementId: 'hf-mass-uf' },

    // GF Walls
    {
      type: 'createWall',
      id: 'hf-w-gf-s',
      name: 'GF south wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X0, yMm: 0 },
      end: { xMm: GF_X1, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-e',
      name: 'GF east wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X1, yMm: 0 },
      end: { xMm: GF_X1, yMm: D },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
