/** @typedef {Record<string, unknown>} BimCommand */

/*
 * Canonical seed: the demo "one-family home" project.
 * Rebuilt from scratch per spec/target-house-seed.md (v3 boolean-subtraction massing)
 * and claude-skills/sketch-to-bim/SKILL.md. Visual ground truth:
 * spec/target-house.jpeg.
 *
 * Coordinate convention (plan):
 *   +xMm = east, +yMm = north (south facade is at y=0, viewed from SSW)
 *   Heights use zMm (engine z = render Y).
 */

// ── Dimensional constants ─────────────────────────────────────────────
const TOTAL_W = 12000; // Total building width (UF width)
const GF_W = 8000; // Ground floor width (2/3 of TOTAL_W)
const D = 16000; // Building depth (1:2 ratio for GF)
const F2F = 3000; // Floor-to-floor height
const WALL_T = 250; // Standard wall thickness
const SHELL_T = 500; // Thick wrapper shell (approx 0.5 units)

const CANTILEVER = 4000; // 1/3 of TOTAL_W
const UF_X0 = 0;
const UF_X1 = TOTAL_W;
const GF_X0 = CANTILEVER;
const GF_X1 = TOTAL_W;

const LOGGIA_SETBACK = 1000; // Recessed frontal plane

// Plinth (Material D)
const PLINTH_EXT = 500; // mm extension

// Roof
const RIDGE_X = 9000; // Ridge off-center to the right (3/4 of 12000)
const EAVE_L = 1500; // West eave height above UF level
const EAVE_R = 2500; // East eave height above UF level (higher ridge offset east)
const SLOPE_DEG = 30;

// Derived Ridge Height
const RIDGE_H_ABS = F2F + EAVE_L + Math.round(RIDGE_X * Math.tan((SLOPE_DEG * Math.PI) / 180));

// Chimney (Spec §3)
const CHIMNEY_W = 2000;
const CHIMNEY_X0 = (TOTAL_W - CHIMNEY_W) / 2; // Center it
const CHIMNEY_X1 = CHIMNEY_X0 + CHIMNEY_W;

/**
 * @returns {BimCommand[]}
 */
export function buildOneFamilyHomeCommands() {
  return [
    // ── Project base point + levels ───────────────────────────────────
    {
      type: 'createProjectBasePoint',
      id: 'hf-pbp',
      positionMm: { xMm: 0, yMm: 0, zMm: 0 },
      angleToTrueNorthDeg: 0,
    },
    { type: 'createLevel', id: 'hf-lvl-ground', name: 'Ground Floor', elevationMm: 0 },
    { type: 'createLevel', id: 'hf-lvl-upper', name: 'First Floor', elevationMm: F2F },

    // === PHASE 1: MASSING ===
    {
      type: 'createMass',
      id: 'hf-mass-gf',
      name: 'Ground floor volume',
      levelId: 'hf-lvl-ground',
      footprintMm: [
        { xMm: GF_X0, yMm: 0 },
        { xMm: GF_X1, yMm: 0 },
        { xMm: GF_X1, yMm: D },
        { xMm: GF_X0, yMm: D },
      ],
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createMass',
      id: 'hf-mass-uf',
      name: 'Upper floor volume',
      levelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: UF_X0, yMm: 0 },
        { xMm: UF_X1, yMm: 0 },
        { xMm: UF_X1, yMm: D },
        { xMm: UF_X0, yMm: D },
      ],
      heightMm: 4000,
      materialKey: 'white_render',
    },

    // === PHASE 2: SKELETON ===
    { type: 'deleteElement', elementId: 'hf-mass-gf' },
    { type: 'deleteElement', elementId: 'hf-mass-uf' },

    // GF Walls
    {
      type: 'createWall',
      id: 'hf-w-gf-s',
      name: 'GF south wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X0, yMm: 0 },
      end: { xMm: GF_X1, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-e',
      name: 'GF east wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X1, yMm: 0 },
      end: { xMm: GF_X1, yMm: D },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-n',
      name: 'GF north wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X1, yMm: D },
      end: { xMm: GF_X0, yMm: D },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-gf-w',
      name: 'GF west wall',
      levelId: 'hf-lvl-ground',
      start: { xMm: GF_X0, yMm: D },
      end: { xMm: GF_X0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: F2F,
      materialKey: 'white_cladding',
    },

    // UF Shell Side Walls (Thick white band)
    {
      type: 'createWall',
      id: 'hf-w-uf-e',
      name: 'UF east shell wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X1, yMm: 0 },
      end: { xMm: UF_X1, yMm: D },
      thicknessMm: SHELL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-w',
      name: 'UF west shell wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X0, yMm: D },
      end: { xMm: UF_X0, yMm: 0 },
      thicknessMm: SHELL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-n',
      name: 'UF north wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X1, yMm: D },
      end: { xMm: UF_X0, yMm: D },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },

    // UF Recessed Front Wall (at y=LOGGIA_SETBACK)
    // Split into 3 zones for the facade composition
    {
      type: 'createWall',
      id: 'hf-w-uf-s-l',
      name: 'UF south wall left',
      levelId: 'hf-lvl-upper',
      start: { xMm: UF_X0 + SHELL_T, yMm: LOGGIA_SETBACK },
      end: { xMm: CHIMNEY_X0, yMm: LOGGIA_SETBACK },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-s-c',
      name: 'UF south wall center (recessed plane)',
      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X0, yMm: LOGGIA_SETBACK },
      end: { xMm: CHIMNEY_X1, yMm: LOGGIA_SETBACK },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-uf-s-r',
      name: 'UF south wall right',
      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X1, yMm: LOGGIA_SETBACK },
      end: { xMm: UF_X1 - SHELL_T, yMm: LOGGIA_SETBACK },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_render',
    },

    // Terrace enclosure wall (Spec §2 "recessed vertical glass wall")
    // Sits at the ridge line (x=9000), from terrace start (y=D/2) to back (y=D)
    {
      type: 'createWall',
      id: 'hf-w-terrace-glass',
      name: 'Terrace vertical glass wall',
      levelId: 'hf-lvl-upper',
      start: { xMm: RIDGE_X, yMm: D / 2 },
      end: { xMm: RIDGE_X, yMm: D },
      thicknessMm: 100,
      heightMm: 4000,
      materialKey: 'glass_clear',
      isCurtainWall: true,
    },

    // Floor slabs
    {
      type: 'createFloor',
      id: 'hf-flr-ground',
      name: 'Ground floor slab + plinth',
      levelId: 'hf-lvl-ground',
      boundaryMm: [
        { xMm: GF_X0 - PLINTH_EXT, yMm: -PLINTH_EXT },
        { xMm: GF_X1 + PLINTH_EXT, yMm: -PLINTH_EXT },
        { xMm: GF_X1 + PLINTH_EXT, yMm: D + PLINTH_EXT },
        { xMm: GF_X0 - PLINTH_EXT, yMm: D + PLINTH_EXT },
      ],
      materialKey: 'white_render',
    },
    {
      type: 'createFloor',
      id: 'hf-flr-upper',
      name: 'First floor slab (thick wrapper bottom)',
      levelId: 'hf-lvl-upper',
      boundaryMm: [
        { xMm: UF_X0, yMm: 0 },
        { xMm: UF_X1, yMm: 0 },
        { xMm: UF_X1, yMm: D },
        { xMm: UF_X0, yMm: D },
      ],
      thicknessMm: SHELL_T,
      materialKey: 'white_render',
    },

    // === PHASE 3: ENVELOPE ===
    {
      type: 'createRoof',
      id: 'hf-roof-main',
      name: 'Upper-volume asymmetric gable',
      referenceLevelId: 'hf-lvl-upper',
      footprintMm: [
        { xMm: UF_X0, yMm: 0 },
        { xMm: UF_X1, yMm: 0 },
        { xMm: UF_X1, yMm: D },
        { xMm: UF_X0, yMm: D },
      ],
      roofGeometryMode: 'asymmetric_gable',
      ridgeOffsetTransverseMm: RIDGE_X - TOTAL_W / 2, // Engine expects offset from centre
      eaveHeightLeftMm: EAVE_L,
      eaveHeightRightMm: EAVE_R,
      slopeDeg: SLOPE_DEG,
      overhangMm: 0, // Wrapper shell is flush
      materialKey: 'white_render',
    },

    // Attach walls
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-s-l', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-s-c', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-s-r', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-e', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-w', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-uf-n', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-terrace-glass', roofId: 'hf-roof-main' },

    // Roof Cutout (Spec §2)
    // Subtract from ridge (x=9000) to gutter (x=12000) for the back half of the building
    {
      type: 'createRoofOpening',
      id: 'hf-roof-cutout',
      name: 'Terrace roof cutout',
      hostRoofId: 'hf-roof-main',
      boundaryMm: [
        { xMm: RIDGE_X, yMm: D / 2 },
        { xMm: UF_X1, yMm: D / 2 },
        { xMm: UF_X1, yMm: D },
        { xMm: RIDGE_X, yMm: D },
      ],
    },

    // Picture-frame Sweep (The crisp edge from the image)
    // Path: front face outline (y=0)
    {
      type: 'createSweep',
      id: 'hf-sw-frame',
      name: 'Wrapper shell front frame',
      levelId: 'hf-lvl-upper',
      pathMm: [
        { xMm: 0, yMm: 0, zMm: 0 },
        { xMm: TOTAL_W, yMm: 0, zMm: 0 },
        { xMm: TOTAL_W, yMm: 0, zMm: EAVE_R },
        { xMm: RIDGE_X, yMm: 0, zMm: RIDGE_H_ABS - F2F },
        { xMm: 0, yMm: 0, zMm: EAVE_L },
        { xMm: 0, yMm: 0, zMm: 0 },
      ],
      profileMm: [
        { uMm: -SHELL_T / 2, vMm: -50 },
        { uMm: SHELL_T / 2, vMm: -50 },
        { uMm: SHELL_T / 2, vMm: 50 },
        { uMm: -SHELL_T / 2, vMm: 50 },
      ],
      profilePlane: 'work_plane',
      materialKey: 'white_render',
    },

    // === PHASE 4: OPENINGS ===
    // Ground south windows
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-1',
      name: 'GF south window 1',
      wallId: 'hf-w-gf-s',
      alongT: 0.25,
      widthMm: 800,
      heightMm: 2000,
      sillHeightMm: 200,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-gf-s-2',
      name: 'GF south window 2 (stair)',
      wallId: 'hf-w-gf-s',
      alongT: 0.5,
      widthMm: 800,
      heightMm: 2000,
      sillHeightMm: 200,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'insertDoorOnWall',
      id: 'hf-door-front',
      name: 'Front door',
      wallId: 'hf-w-gf-s',
      alongT: 0.9,
      widthMm: 1000,
      familyTypeId: 'door_hinged_single',
    },

    // Upper Front Openings
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-uf-trap',
      name: 'Upper left trapezoidal window',
      wallId: 'hf-w-uf-s-l',
      alongT: 0.5,
      widthMm: 2500,
      heightMm: 2000,
      sillHeightMm: 500,
      familyTypeId: 'window_casement_fixed',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'outlineKind',
      value: 'gable_trapezoid',
    },
    {
      type: 'updateElementProperty',
      elementId: 'hf-win-uf-trap',
      key: 'attachedRoofId',
      value: 'hf-roof-main',
    },

    // Curtain wall on the right
    {
      type: 'insertWindowOnWall',
      id: 'hf-win-uf-curtain',
      name: 'Upper right curtain wall',
      wallId: 'hf-w-uf-s-r',
      alongT: 0.5,
      widthMm: 3500,
      heightMm: 2800,
      sillHeightMm: 0,
      familyTypeId: 'window_curtain_wall',
    },
    // Mullion logic would be here if supported, or via curtain wall family

    // === PHASE 5: INTERIOR ===
    {
      type: 'createStair',
      id: 'hf-stair-main',
      name: 'Interior staircase',
      baseLevelId: 'hf-lvl-ground',
      topLevelId: 'hf-lvl-upper',
      runStartMm: { xMm: GF_X0 + 4000, yMm: 500 },
      runEndMm: { xMm: GF_X0 + 4000, yMm: 5000 },
      widthMm: 1000,
      riserMm: 176,
      treadMm: 250,
    },

    {
      type: 'createRoomOutline',
      id: 'hf-room-gf',
      name: 'Ground Floor Living',
      levelId: 'hf-lvl-ground',
      outlineMm: [
        { xMm: GF_X0 + 200, yMm: 200 },
        { xMm: GF_X1 - 200, yMm: 200 },
        { xMm: GF_X1 - 200, yMm: D - 200 },
        { xMm: GF_X0 + 200, yMm: D - 200 },
      ],
      programmeCode: 'living',
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-uf-main',
      name: 'Master Suite',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: UF_X0 + SHELL_T + 200, yMm: LOGGIA_SETBACK + 200 },
        { xMm: UF_X1 - SHELL_T - 200, yMm: LOGGIA_SETBACK + 200 },
        { xMm: UF_X1 - SHELL_T - 200, yMm: D / 2 - 200 },
        { xMm: UF_X0 + SHELL_T + 200, yMm: D / 2 - 200 },
      ],
      programmeCode: 'bedroom',
    },
    {
      type: 'createRoomOutline',
      id: 'hf-room-terrace',
      name: 'Roof Terrace',
      levelId: 'hf-lvl-upper',
      outlineMm: [
        { xMm: RIDGE_X + 200, yMm: D / 2 + 200 },
        { xMm: UF_X1 - SHELL_T - 200, yMm: D / 2 + 200 },
        { xMm: UF_X1 - SHELL_T - 200, yMm: D - 200 },
        { xMm: RIDGE_X + 200, yMm: D - 200 },
      ],
      programmeCode: 'terrace',
    },

    // === PHASE 6: DETAIL ===
    // Chimney protrusion (Spec §3 Center volume)
    // It's a vertical siding volume in front of hf-w-uf-s-c
    {
      type: 'createWall',
      id: 'hf-w-chimney-s',
      name: 'Chimney face',
      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X0, yMm: 0 },
      end: { xMm: CHIMNEY_X1, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-chimney-w',
      name: 'Chimney side west',
      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X0, yMm: LOGGIA_SETBACK },
      end: { xMm: CHIMNEY_X0, yMm: 0 },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_cladding',
    },
    {
      type: 'createWall',
      id: 'hf-w-chimney-e',
      name: 'Chimney side east',
      levelId: 'hf-lvl-upper',
      start: { xMm: CHIMNEY_X1, yMm: 0 },
      end: { xMm: CHIMNEY_X1, yMm: LOGGIA_SETBACK },
      thicknessMm: WALL_T,
      heightMm: 6000,
      materialKey: 'white_cladding',
    },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-chimney-s', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-chimney-w', roofId: 'hf-roof-main' },
    { type: 'attachWallTopToRoof', wallId: 'hf-w-chimney-e', roofId: 'hf-roof-main' },

    // Railing (Spec §3 Balcony)
    // Across entire upper front width at y=0 (inner edge of shell)
    {
      type: 'createRailing',
      id: 'hf-rail-balcony',
      name: 'Upper balcony railing',
      pathMm: [
        { xMm: UF_X0 + SHELL_T, yMm: 50 },
        { xMm: CHIMNEY_X0, yMm: 50 },
        // Gap for chimney? No, "across the entire upper front width"
        // But the chimney is at y=0. So railing stops at chimney.
      ],
    },
    {
      type: 'createRailing',
      id: 'hf-rail-balcony-2',
      name: 'Upper balcony railing 2',
      pathMm: [
        { xMm: CHIMNEY_X1, yMm: 50 },
        { xMm: UF_X1 - SHELL_T, yMm: 50 },
      ],
    },

    // === PHASE 7: DOCUMENTATION ===
    {
      type: 'saveViewpoint',
      id: 'vp-main-iso',
      name: 'Main isometric (Spec §5 front-left)',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: -8000, yMm: -12000, zMm: 12000 },
        target: { xMm: 6000, yMm: 8000, zMm: 3000 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
    {
      type: 'saveViewpoint',
      id: 'vp-front-elev',
      name: 'Front elevation (south)',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: 6000, yMm: -12000, zMm: 4500 },
        target: { xMm: 6000, yMm: 8000, zMm: 4500 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
    {
      type: 'saveViewpoint',
      id: 'vp-terrace',
      name: 'Roof Terrace view',
      mode: 'orbit_3d',
      camera: {
        position: { xMm: 14000, yMm: 14000, zMm: 6000 },
        target: { xMm: 10000, yMm: 12000, zMm: 4000 },
        up: { xMm: 0, yMm: 0, zMm: 1 },
      },
    },
  ];
}

response.output:
/**
 * Visual checkpoint harness for `nightshift/seed-target-house/`.
 *
 * Loads the materialised seed fixture (regen via
 *   node scripts/build-seed-snapshot.mjs
 * after every bundle change), drives the workspace to 3D mode,
 * hydrates the Zustand store directly via the `__bimStore` window
 * hook (skips the bootstrap → snapshot fetch path; cleaner for the
 * agent's checkpoint loop), optionally activates a SKB-16 viewpoint,
 * and saves the rendered viewport to
 *   packages/web/test-results/seed-target-house-<viewpoint>-actual.png
 * for side-by-side comparison with `spec/target-house-vis-colored.png`.
 *
 * Per `claude-skills/sketch-to-bim/SKILL.md` § "The refine loop", the
 * agent reads the rendered PNG with its own multimodal vision after
 * each phase commit. Each phase:
 *   1. node scripts/build-seed-snapshot.mjs    # regenerate fixture
 *   2. pnpm --filter @bim-ai/web exec playwright test seed-target-house
 *   3. open the four PNGs in test-results/, compare to the colour study.
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { expect, test, type Page } from '@playwright/test';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const FIXTURE_PATH = path.join(__dirname, '__fixtures__', 'seed-target-house-snapshot.json');

if (!fs.existsSync(FIXTURE_PATH)) {
  throw new Error(
    `Fixture missing: ${FIXTURE_PATH}\nRun: node scripts/build-seed-snapshot.mjs from repo root.`,
  );
}

type SnapshotShape = {
  modelId: string;
  revision: number;
  elements: Record<string, { kind?: string; id?: string }>;
  violations: unknown[];
};

function loadSnapshot(): SnapshotShape {
  return JSON.parse(fs.readFileSync(FIXTURE_PATH, 'utf8')) as SnapshotShape;
}

async function bootWorkspace(page: Page) {
  await page.addInitScript(() => {
    localStorage.setItem('bim.welcome.dismissed', '1');
    localStorage.setItem('bim.onboarding-completed', 'true');
    localStorage.setItem('bim.workspaceLayout', 'split_plan_3d');
  });
  // The store hydration path bypasses the API entirely, but the workspace
  // still pings these endpoints during boot — stub with empty payloads to
  // avoid uncaught fetch rejections in the console.
  await page.route('**/api/bootstrap', async (route) => {
    await route.fulfill({ status: 200, contentType: 'application/json', body: '{"projects":[]}' });
  });
  await page.route('**/api/models/*/comments**', async (route) =>
    route.fulfill({ status: 200, body: '{}' }),
  );
  await page.route('**/api/models/*/activity**', async (route) =>
    route.fulfill({ status: 200, body: '{"events":[]}' }),
  );
  await page.route('**/api/building-presets**', async (route) =>
    route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: '{"presets":{"residential":{}}}',
    }),
  );
  await page.goto('/');
  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30_000 });
}

async function ensure3dMode(page: Page) {
  const viewport = page.getByTestId('orbit-3d-viewport');
  if (await viewport.isVisible({ timeout: 1_000 }).catch(() => false)) return;

  const splitTab = page.getByRole('tab', { name: /Plan \+ 3D|3D/i }).first();
  if (await splitTab.isVisible({ timeout: 5_000 }).catch(() => false)) {
    await splitTab.click();
  } else {
    await page.keyboard.press('2');
  }
  await expect(viewport).toBeVisible({ timeout: 30_000 });
}

async function hydrateStore(page: Page, snapshot: SnapshotShape) {
  await page.evaluate((snap) => {
    type StoreShape = {
      getState: () => {
        hydrateFromSnapshot: (s: SnapshotShape) => void;
      };
    };
    const win = window as unknown as { __bimStore?: StoreShape };
    if (!win.__bimStore) throw new Error('window.__bimStore not exposed');
    win.__bimStore.getState().hydrateFromSnapshot(snap);
  }, snapshot);
  // Allow React to commit the new elements + Three.js to build meshes.
  await page.waitForTimeout(800);
}

type ViewpointId = 'fit' | 'vp-main-iso' | 'vp-front-elev' | 'vp-side-elev-east' | 'vp-rear-axo';

async function activateViewpoint(
  page: Page,
  vp: ViewpointId,
  snapshot: SnapshotShape,
): Promise<boolean> {
  if (vp === 'fit') return false;
  const vpEl = Object.values(snapshot.elements).find(
    (el) => el?.kind === 'viewpoint' && el?.id === vp,
  ) as undefined | { camera?: { position: Vec3; target: Vec3; up: Vec3 } };
  if (!vpEl) return false;
  type Vec3 = { xMm: number; yMm: number; zMm: number };
  const camera = vpEl.camera;
  if (!camera) return false;
  await page.evaluate(
    ([vpId, cam]) => {
      type StoreActions = {
        setActiveViewpointId?: (id: string) => void;
        setOrbitCameraFromViewpointMm?: (pose: {
          position: { xMm: number; yMm: number; zMm: number };
          target: { xMm: number; yMm: number; zMm: number };
          up: { xMm: number; yMm: number; zMm: number };
        }) => void;
      };
      const win = window as unknown as { __bimStore?: { getState: () => StoreActions } };
      const state = win.__bimStore?.getState();
      state?.setActiveViewpointId?.(vpId as string);
      state?.setOrbitCameraFromViewpointMm?.(
        cam as {
          position: { xMm: number; yMm: number; zMm: number };
          target: { xMm: number; yMm: number; zMm: number };
          up: { xMm: number; yMm: number; zMm: number };
        },
      );
    },
    [vp, camera] as const,
  );
  await page.waitForTimeout(1_500);
  return true;
}

async function captureViewpoint(page: Page, label: string, useFit: boolean) {
  const viewport = page.locator('[data-testid="orbit-3d-viewport"]');
  await expect(viewport).toBeVisible({ timeout: 30_000 });
  if (useFit) {
    // No authored viewpoint — frame the model with F-key fit-to-screen.
    await viewport.click({ position: { x: 100, y: 100 } });
    await page.keyboard.press('f');
    await page.waitForTimeout(2_500);
  } else {
    // Authored viewpoint — let the saved camera settle.
    await page.waitForTimeout(2_000);
  }
  const outPath = `test-results/seed-target-house-${label}-actual.png`;
  await viewport.screenshot({ path: outPath });
  return outPath;
}

test.describe('seed-target-house', () => {
  test.beforeEach(async ({ page }) => {
    await bootWorkspace(page);
    await ensure3dMode(page);
    const snapshot = loadSnapshot();
    await hydrateStore(page, snapshot);
    await ensure3dMode(page);
  });

  test('main iso', async ({ page }) => {
    const snapshot = loadSnapshot();
    const activated = await activateViewpoint(page, 'vp-main-iso', snapshot);
    const out = await captureViewpoint(page, 'main-iso', !activated);
    expect(fs.existsSync(out)).toBe(true);
  });

  test('front elevation', async ({ page }) => {
    const snapshot = loadSnapshot();
    const activated = await activateViewpoint(page, 'vp-front-elev', snapshot);
    const out = await captureViewpoint(page, 'front-elev', !activated);
    expect(fs.existsSync(out)).toBe(true);
  });

  test('east side elevation', async ({ page }) => {
    const snapshot = loadSnapshot();
    const activated = await activateViewpoint(page, 'vp-side-elev-east', snapshot);
    const out = await captureViewpoint(page, 'side-elev-east', !activated);
    expect(fs.existsSync(out)).toBe(true);
  });

  test('rear axonometric', async ({ page }) => {
    const snapshot = loadSnapshot();
    const activated = await activateViewpoint(page, 'vp-rear-axo', snapshot);
    const out = await captureViewpoint(page, 'rear-axo', !activated);
    expect(fs.existsSync(out)).toBe(true);
  });
});

#!/usr/bin/env node
/**
 * BIM AI CLI — agent-facing workflows + snapshot transport.
 * Node 20+ (fetch + WebSocket).
 */
import fs from 'node:fs/promises';
import path from 'node:path';
import { stdin } from 'node:process';

import { buildOneFamilyHomeCommands } from './lib/one-family-home-commands.mjs';

const base = (
  process.env.BIM_AI_BASE_URL ?? process.env.BIM_AI_API_ROOT ?? 'http://127.0.0.1:8500'
).replace(/\/$/, '');

function slurpStdin() {
  return new Promise((resolve, reject) => {
    let d = '';
    stdin.setEncoding('utf8');
    stdin.on('data', (c) => {
      d += c;
    });
    stdin.on('end', () => resolve(d));
    stdin.on('error', reject);
  });
}

async function readPayloadOrStdin(pathArg) {
  if (pathArg && pathArg !== '-') {
    return fs.readFile(pathArg, 'utf8');
  }
  if (stdin.isTTY) {
    console.error('Pass a JSON file path, or pipe JSON on stdin (use - for explicit stdin).');
    process.exit(1);
  }
  return slurpStdin();
}

function commandsFromBundleJson(blob) {
  if (Array.isArray(blob)) return blob;
  if (blob && typeof blob === 'object' && Array.isArray(blob.commands)) return blob.commands;
  console.error('Bundle must be a JSON array or { "commands": [...] }.');
  process.exit(1);
}

function wsUrl(modelId) {
  const u = new URL(base);
  u.protocol = u.protocol === 'https:' ? 'wss:' : 'ws:';
  u.pathname = `/ws/${encodeURIComponent(modelId)}`;
  u.search = '';
  return u.href;
}

async function fetchJson(method, url, bodyObj) {
  const res = await fetch(url, {
    method,
    headers: bodyObj ? { 'content-type': 'application/json' } : undefined,
    body: bodyObj ? JSON.stringify(bodyObj) : undefined,
  });
  const text = await res.text();
  let json;
  try {
    json = JSON.parse(text);
  } catch {
    json = { raw: text };
  }
  if (!res.ok) {
    console.error(JSON.stringify({ status: res.status, body: json }, null, 2));
    process.exit(1);
  }
  return json;
}

async function fetchOkText(method, url) {
  const res = await fetch(url, {
    method,
    headers: { accept: 'model/gltf+json,application/json,text/plain;q=0.9,*/*;q=0.1' },
  });
  const text = await res.text();
  if (!res.ok) {
    console.error(JSON.stringify({ status: res.status, sample: text.slice(0, 2000) }, null, 2));
    process.exit(1);
  }
  return text;
}

async function fetchOkBytes(method, url) {
  const res = await fetch(url, {
    method,
    headers: {
      accept:
        'application/octet-stream,model/gltf-binary,*/*;q=0.8',
    },
  });
  const buf = Buffer.from(await res.arrayBuffer());
  if (!res.ok) {
    console.error(JSON.stringify({ status: res.status, bytes: buf.length }, null, 2));
    process.exit(1);
  }
  return buf;
}

async function snapshot(modelId) {
  const json = await fetchJson('GET', `${base}/api/models/${encodeURIComponent(modelId)}/snapshot`);
  console.log(JSON.stringify(json, null, 2));
}

// FED-01 polish: federation subcommands.

function parseAlignMode(s, fallback = 'origin_to_origin') {
  if (s === 'origin_to_origin' || s === 'project_origin' || s === 'shared_coords') return s;
  if (s == null) return fallback;
  console.error(
    `Unknown --align value: '${s}'. Use origin_to_origin | project_origin | shared_coords.`,
  );
  process.exit(1);
}

function parsePosTriple(s) {
  if (!s) {
    console.error('--pos x,y,z required');
    process.exit(1);
  }
  const parts = String(s)
    .split(',')
    .map((t) => Number(t.trim()));
  if (parts.length !== 3 || parts.some((n) => !Number.isFinite(n))) {
    console.error(`Invalid --pos value: '${s}'. Expected three comma-separated numbers (mm).`);
    process.exit(1);
  }
  return { xMm: parts[0], yMm: parts[1], zMm: parts[2] };
}

async function cmdLinkCreate(modelId, userId, sourceUuid, posTriple, alignMode, name, vis) {
  if (!sourceUuid) {
    console.error('link requires --source <uuid>');
