          else if (a === '--kind' && rest[i + 1]) assetKind = rest[++i];
          else if (a === '--tags' && rest[i + 1]) tagsArg = rest[++i];
          else if (a === '--description' && rest[i + 1]) description = rest[++i];
        }
        if (!name || !category) {
          console.error('asset index requires --name <name> --category <category>');
