        const [x0, y0, x1, y1] = coords.map(Number);
        const cmd = {
          type: 'createPlanRegion',
          levelId,
          outlineMm: [
            { xMm: x0, yMm: y0 },
            { xMm: x1, yMm: y0 },
            { xMm: x1, yMm: y1 },
            { xMm: x0, yMm: y1 },
          ],
