        const modelArg = argv[argv.indexOf('--model') + 1] ?? modelId;
        if (!modelArg) { console.error('jobs submit requires --model <id> or BIM_AI_MODEL_ID'); process.exit(1); }
        const inputsIdx = argv.indexOf('--inputs');
